#include<bits/stdc++.h>
using namespace std;
long long n, qujian[500001],m;
class node {
	public:
		long long x, y, zong;
		int l;
		int r;
		long long lan;

} a[800001];
void cxy(long long b, int x1, int y1) {
	a[b].x = x1;
	a[b].y = y1;
}
long long g(long long b, int x, int y) {
	if (x == y) {
		a[b].l = 0;
		a[b].r = 0;
		a[b].zong = qujian[x];
		return qujian[x];
	} else {
		long long zuo = 0;
		//cout<<x<<" "<<y<<"\n";
		a[b].l = b * 2;
		cxy(b * 2, x, ((y + x) / 2));
		zuo += g(b * 2, x, ((y + x) / 2));
		a[b].r = b * 2 + 1;
		cxy(b * 2 + 1, ((x + y) / 2 + 1), y);
		zuo += g(b * 2 + 1, ((x + y) / 2 + 1), y);
		a[b].zong = zuo;
		return zuo;
	}
}
void down(long long b) {
    if (a[b].lan != 0 && a[b].l != 0) {
	int le = a[b].l;
	int ri = a[b].r;
	a[le].lan ^= a[b].lan;
	a[le].zong = (a[le].y - a[le].x + 1)-a[le].zong;
	a[ri].lan ^= a[b].lan;
	 a[ri].zong = (a[ri].y - a[ri].x + 1)-a[ri].zong;
	a[b].lan=0;
    }
}
void xx(long long b, int x, int y) {
	if (a[b].x == x && a[b].y == y) {
        a[b].lan ^= 1;
        a[b].zong = (y - x + 1)-a[b].zong;
        return;
    }
	down(b);

	if (x > a[a[b].l].y) {
		xx(b * 2 + 1, x, y);
	} else if (y < a[a[b].r].x) {
		xx(b * 2, x, y);
	} else {
		xx(b * 2, x, a[a[b].l].y);
		xx(b * 2 + 1, a[a[b].r].x, y);
	}
    a[b].zong = a[a[b].l].zong + a[a[b].r].zong; 
}

long long c(long long b, int x, int y) {
    if(b==0) return 0;
	if (a[b].x == x && a[b].y == y) {
		return a[b].zong;
	}
	long long zong = 0;
	down(b);
	if (x > a[a[b].l].y) {
		return c(b * 2 + 1, x, y);
	} else if (y < a[a[b].r].x) {
		return c(b * 2, x, y);
	} else {
		zong += c(b * 2, x, a[a[b].l].y);
		zong += c(b * 2 + 1, a[a[b].r].x, y);
		return zong;
	}

}


int main() {

	cin >> n >> m;

	for (int i = 1; i <= n; i++) {
		qujian[i]=0;
	}

	cxy(1, 1, n);
	g(1, 1, n);
	for (int i = 1; i <= m; i++) {
		long long j;
		cin >> j;
		if (j == 0) {
			long long x, y;
			cin >> x >> y;
            if(x>y) swap(x,y);
			xx(1, x, y);
		} else {
			long long x, y;
			cin >> x >> y;
            if(x>y) swap(x,y);
			cout << c(1, x, y) << "\n";
		}
	}
	return 0;
}
